1. Update Snake.gd to handle input queueing:
   ```gdscript
   extends Node2D
   const CELL_SIZE = 32
   const UP = Vector2i(0, -1)
   const DOWN = Vector2i(0, 1)
   const LEFT = Vector2i(-1, 0)
   const RIGHT = Vector2i(1, 0)

   var body: Array[Vector2i] = [Vector2i(10, 10), Vector2i(9, 10), Vector2i(8, 10)]
   var heading: Vector2i = RIGHT
   var queued_heading: Vector2i = RIGHT

   func _draw():
       for i in body.size():
           var cell = body[i]
           var color = Color.GREEN if i == 0 else Color.LIME_GREEN
           draw_rect(Rect2(cell.x * CELL_SIZE, cell.y * CELL_SIZE, CELL_SIZE, CELL_SIZE), color, true)

   func queue_direction(new_direction: Vector2i):
       # Reject direct reversal (opposite direction)
       if new_direction + heading != Vector2i.ZERO:
           queued_heading = new_direction

   func move():
       heading = queued_heading # Apply queued heading at tick boundary
       var new_head = body[0] + heading
       body.insert(0, new_head)
       body.pop_back()
       queue_redraw()
   ```

2. Update Game.gd to handle input:
   ```gdscript
   extends Node2D
   @onready var snake = $Snake
   @onready var game_tick = $GameTick

   func _ready():
       game_tick.timeout.connect(_on_game_tick)

   func _process(_delta):
       if Input.is_action_just_pressed("move_up"):
           snake.queue_direction(Vector2i(0, -1))
       elif Input.is_action_just_pressed("move_down"):
           snake.queue_direction(Vector2i(0, 1))
       elif Input.is_action_just_pressed("move_left"):
           snake.queue_direction(Vector2i(-1, 0))
       elif Input.is_action_just_pressed("move_right"):
           snake.queue_direction(Vector2i(1, 0))

   func _on_game_tick():
       snake.move()
   ```

1. Update Apple.gd with respawn logic:
   ```gdscript
   extends Node2D
   const CELL_SIZE = 32
   const GRID_WIDTH = 20
   const GRID_HEIGHT = 20
   var position_grid: Vector2i = Vector2i(15, 10)

   func _draw():
       draw_rect(Rect2(position_grid.x * CELL_SIZE, position_grid.y * CELL_SIZE, CELL_SIZE, CELL_SIZE), Color.RED, true)

   func respawn(snake_body: Array[Vector2i]):
       var empty_cells: Array[Vector2i] = []
       for x in range(GRID_WIDTH):
           for y in range(GRID_HEIGHT):
               var cell = Vector2i(x, y)
               if cell not in snake_body:
                   empty_cells.append(cell)

       if empty_cells.size() > 0:
           position_grid = empty_cells[randi() % empty_cells.size()]
           queue_redraw()
   ```

2. Update Snake.gd to add growth:
   ```gdscript
   var pending_growth: int = 0

   func move():
       heading = queued_heading
       var new_head = body[0] + heading
       body.insert(0, new_head)

       if pending_growth > 0:
           pending_growth -= 1
       else:
           body.pop_back() # Only remove tail if not growing

       queue_redraw()

   func grow():
       pending_growth += 1
   ```

