1. Update Snake.gd to add collision checking:
   ```gdscript
   const GRID_WIDTH = 20
   const GRID_HEIGHT = 20

   func check_collision() -> bool:
       var head = body[0]

       # Wall collision
       if head.x < 0 or head.x >= GRID_WIDTH or head.y < 0 or head.y >= GRID_HEIGHT:
           return true

       # Self collision (check if head collides with any body segment except head)
       for i in range(1, body.size()):
           if head == body[i]:
               return true

       return false
   ```

2. Update Game.gd to handle game over:
   ```gdscript
   var is_game_over: bool = false

   func _ready():
       game_tick.timeout.connect(_on_game_tick)

   func _process(_delta):
       if is_game_over:
           if Input.is_action_just_pressed("ui_accept"): # Space or Enter to restart
               restart_game()
           return

       # Input handling (existing code)
       if Input.is_action_just_pressed("move_up"):
           snake.queue_direction(Vector2i(0, -1))
       # ... etc

   func _on_game_tick():
       if is_game_over:
           return

       snake.move()

       if snake.check_collision():
           game_over()
           return

       if snake.body[0] == apple.position_grid:
           snake.grow()
           apple.respawn(snake.body)

   func game_over():
       is_game_over = true
       game_tick.stop()
       print("Game Over! Press Space/Enter to restart")

   func restart_game():
       get_tree().reload_current_scene()
   ```

1. Create HighScore.gd autoload script:
   ```gdscript
   extends Node
   const SAVE_PATH = "user://highscore.save"
   var high_score: int = 0

   func _ready():
       load_high_score()

   func load_high_score():
       if not FileAccess.file_exists(SAVE_PATH):
           high_score = 0
           return

       var file = FileAccess.open(SAVE_PATH, FileAccess.READ)
       if file:
           var data = file.get_as_text()
           file.close()
           high_score = int(data)
       else:
           high_score = 0

   func save_high_score(new_score: int):
       if new_score > high_score:
           high_score = new_score
           var file = FileAccess.open(SAVE_PATH, FileAccess.WRITE)
           if file:
               file.store_string(str(high_score))
               file.close()

   func get_high_score() -> int:
       return high_score
   ```

